### Describe what's wrong
When we create a refreshable materialized view with the EMPTY keyword, this is not stored in metadata, and after backup and restore, it tries to recreate the destination table.
### Does it reproduce on the most recent release?
Yes
### How to reproduce
https://fiddle.clickhouse.com/3e631467-41f5-4bdc-990e-21de0e2c5db6
```sql
DROP DATABASE IF EXISTS test SYNC;
CREATE DATABASE test ENGINE=Atomic;
CREATE  TABLE  IF NOT EXISTS `test`.`mv_src_table` UUID 'dc60928b-ff47-448d-806c-2dc2e06714fb'  (id UInt64) Engine=MergeTree ORDER BY id;
INSERT INTO `test`.`mv_src_table` SELECT number FROM numbers(10);
CREATE  TABLE  IF NOT EXISTS `test`.`mv_refreshable_dst_table` UUID '620be150-bdef-47b2-a295-428dd8e79c97' (id UInt64) Engine=MergeTree ORDER BY id;
CREATE  MATERIALIZED VIEW  IF NOT EXISTS `test`.`mv_refreshable` UUID '98be4ca8-fe55-471a-9c56-2e722a7cd8c1' REFRESH EVERY 1 MINUTE TO `test`.`mv_refreshable_dst_table` EMPTY AS SELECT max(id) AS id FROM `test`.`mv_src_table`;
SHOW CREATE TABLE `test`.`mv_refreshable` FORMAT Vertical;;
SELECT now();
SELECT * FROM system.view_refreshes FORMAT Vertical;
SELECT count() FROM `test`.`mv_refreshable`;
BACKUP DATABASE test TO File('test.zip');
DROP DATABASE test SYNC;
CREATE DATABASE test ENGINE=Atomic;
RESTORE DATABASE test FROM File('test.zip');
SELECT now();
SELECT * FROM system.view_refreshes FORMAT Vertical;
SELECT count() FROM `test`.`mv_refreshable`;
```
